import {{ Injectable }} from '@nestjs/common';
import {{ DiscountService }} from './models/discount.model';
import {{ DiscountServiceRepository }} from './repositories/discount.repository';

@Injectable()
export class DiscountServiceService {{
  constructor(
    private readonly repository: DiscountServiceRepository,
  ) {{}}

  async findAll(): Promise<DiscountService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<DiscountService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<DiscountService>): Promise<DiscountService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<DiscountService>): Promise<DiscountService> {{
    return this.repository.update(id, data);
  }}
}}

"""
discount module - handles core discount functionality
